# Binary Search Tree Dictionary Implementation in C++

Below is a well-structured C++ program that implements a dictionary using a Binary Search Tree (BST). The program allows users to insert words and definitions, search for words, delete words, and display the entire dictionary.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <iomanip>

using namespace std;

// Define the node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class BinarySearchTree {
private:
    Node* root;

    // Helper function to insert a node
    void insert(Node* &node, string word, string definition);

    // Helper function to search for a node
    Node* search(Node* node, string word);

    // Helper function to delete a node
    void deleteNode(Node* &node, string word);

    // Helper function to print the tree
    void printTree(Node* node, int depth = 0);

public:
    BinarySearchTree() : root(nullptr) {}

    // Insert a word and definition
    void insert(string word, string definition) {
        insert(root, word, definition);
    }

    // Search for a word
    Node* search(string word) {
        return search(root, word);
    }

    // Delete a word
    void deleteWord(string word) {
        deleteNode(root, word);
    }

    // Print all words and definitions
    void printDictionary() {
        printTree(root);
    }

    // Helper function to print the tree (in-order traversal)
    void printTree(Node* node, int depth = 0) {
        if (node != nullptr) {
            printTree(node->right, depth + 1);
            cout << setw(10) << left << node->word << " - " << node->definition << endl;
            printTree(node->left, depth + 1);
        }
    }
};

// Helper functions for insertion, search, and deletion
void BinarySearchTree::insert(Node* &node, string word, string definition) {
    if (node == nullptr) {
        node = new Node(word, definition);
        return;
    }

    if (word < node->word) {
        insert(node->left, word, definition);
    } else {
        insert(node->right, word, definition);
    }
}

Node* BinarySearchTree::search(Node* node, string word) {
    if (node == nullptr || node->word == word) {
        return node;
    }

    if (word < node->word) {
        return search(node->left, word);
    } else {
        return search(node->right, word);
    }
}

void BinarySearchTree::deleteNode(Node* &node, string word) {
    if (node == nullptr) {
        return;
    }

    if (word < node->word) {
        deleteNode(node->left, word);
    } else if (word > node->word) {
        deleteNode(node->right, word);
    } else {
        // Node found; delete it
        if (node->left == nullptr) {
            Node* temp = node->right;
            delete node;
            node = temp;
        } else if (node->right == nullptr) {
            Node* temp = node->left;
            delete node;
            node = temp;
        } else {
            // Node has two children; find the in-order successor
            Node* temp = node->right;
            while (temp->left != nullptr) {
                temp = temp->left;
            }

            // Copy the in-order successor's value to current node
            node->word = temp->word;
            node->definition = temp->definition;

            // Delete the in-order successor
            deleteNode(node->right, temp->word);
        }
    }
}

// Main application
int main() {
    BinarySearchTree dict;

    string inputWord, inputDefinition;

    while (true) {
        cout << "Enter a word (or type 'exit' to quit): ";
        getline(cin, inputWord);

        if (inputWord == "exit") {
            break;
        }

        cout << "Enter the definition: ";
        getline(cin, inputDefinition);

        dict.insert(inputWord, inputDefinition);
    }

    cout << "\nDictionary Contents:\n";
    dict.printDictionary();

    return 0;
}
```

