public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://via.placeholder.com/800x600"; // Replace with your image URL
        String outputFilePath = "output.png";

        try {
            BufferedImage originalImage = downloadAndLoadImage(imageUrl);
            BufferedImage filteredImage = applyFilters(originalImage);
            saveImage(filteredImage, outputFilePath);
            System.out.println("Image processed and saved to: " + outputFilePath);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static BufferedImage downloadAndLoadImage(String imageUrl) throws IOException {
        URL url = new URL(imageUrl);
        BufferedImage image = ImageIO.read(url);
        return image;
    }

    private static BufferedImage applyFilters(BufferedImage image) {
        // Apply grayscale filter
        BufferedImage grayscale = new BufferedImage(image.getWidth(), image.getHeight(), BufferedImage.TYPE_INT_RGB);
        for (int x = 0; x < image.getWidth(); x++) {
            for (int y = 0; y < image.getHeight(); y++) {
                int pixel = image.getRGB(x, y);
                int r = (pixel >> 16) & 0xFF;
                int g = (pixel >> 8) & 0xFF;
                int b = (pixel) & 0xFF;
                int gray = (int) (0.2989 * r + 0.5870 * g + 0.1140 * b);
                grayscale.setRGB(x, y, (gray << 16) | (gray << 8) | gray);
            }
        }

        // Optional: Apply sepia tone
        BufferedImage sepia = new BufferedImage(image.getWidth(), image.getHeight(), BufferedImage.TYPE_INT_RGB);
        for (int x = 0; x < image.getWidth(); x++) {
            for (int y = 0; y < image.getHeight(); y++) {
                int pixel = image.getRGB(x, y);
                int r = (pixel >> 16) & 0xFF;
                int g = (pixel >> 8) & 0xFF;
                int b = (pixel) & 0xFF;

                int sepiaR = (int) (0.393 * r + 0.769 * g + 0.189 * b);
                int sepiaG = (int) (0.349 * r + 0.686 * g + 0.106 * b);
                int sepiaB = (int) (0.272 * r + 0.534 * g + 0.112 * b);

                sepia.setRGB(x, y, (sepiaR << 16) | (sepiaG << 8) | sepiaB);
            }
        }

        // Optional: Apply a blur filter
        ConvolveOp blurOp = new ConvolveOp(
            new Kernel(3, 3, new double[]{0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04, 0.04}),
            ConvolveOp.EDGE_NO_OP, new byte[]{0, 0, 0, 0, 1, 0, 0, 0, 0},
            new byte[]{0, 0, 0, 0, 0, 0, 0, 0, 0}
        );
        BufferedImage blurred = new BufferedImage(image.getWidth(), image.getHeight(), BufferedImage.TYPE_INT_RGB);
        ImageIO.write(blurOp.filter(image, blurred, "png"), "PNG", blurred);

        return blurred;
    }

    private static void saveImage(BufferedImage image, String outputPath) throws IOException {
        ImageIO.write(image, "PNG", new File(outputPath));
    }
}
```

