                let temp = Node(successor.value)
                temp.left = successor.left
                temp.right = successor.right

                // Copy the successor's data to the current node
                node!.value = temp.value
                node!.left = deleteNode(node!.left, successor.value)
            }
        }

        return node!
    }

    // Find the minimum value in a subtree
