Here's a well-structured JavaScript program that implements the binary search algorithm to find a specific value in an array:

```javascript
function binarySearch(arr, target) {
    // Define the boundaries of the search
    let left = 0;
    let right = arr.length - 1;

    while (left <= right) {
        // Find the middle index
        const mid = Math.floor((left + right) / 2);

        // Check if the target is at the middle
        if (arr[mid] === target) {
            return mid; // Target found
        }

        // If target is smaller than the middle element, search the left half
        if (arr[mid] > target) {
            right = mid - 1;
        } else {
            // Otherwise, search the right half
            left = mid + 1;
        }
    }

    // Target not found in the array
    return -1;
}

// Example usage:
